1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	};
15	
16	const itemPremium = (item: Item): number => {
17	  const base = BASE_PREMIUMS[item.type];
18	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
19	  return base + firstInsuranceSurcharge;
20	};
21	
22	const quoteItems = (items: Item[]): number => {
23	  const itemsTotal = items.reduce((sum, item) => sum + itemPremium(item), 0);
24	  return Math.ceil(itemsTotal + PROCESSING_FEE);
25	};
26	
27	export const runScenario = (input: Scenario): { results: { premium: number }[] } => {
28	  const results = input.steps.map((step) => ({ premium: quoteItems(step.items) }));
29	  return { results };
30	};
